from flask import Flask, request, jsonify
import pandas as pd
import tensorflow as tf
from tensorflow import keras
from tensorflow.keras import layers
import os

app = Flask(__name__)
UPLOAD_FOLDER = 'uploads'
os.makedirs(UPLOAD_FOLDER, exist_ok=True)

def create_model():
    model = keras.Sequential([
        layers.Conv2D(32, (3, 3), activation='relu', input_shape=(150, 150, 3)),
        layers.MaxPooling2D(pool_size=(2, 2)),
        layers.Conv2D(64, (3, 3), activation='relu'),
        layers.MaxPooling2D(pool_size=(2, 2)),
        layers.Conv2D(128, (3, 3), activation='relu'),
        layers.MaxPooling2D(pool_size=(2, 2)),
        layers.Flatten(),
        layers.Dense(128, activation='relu'),
        layers.Dense(10, activation='softmax')
    ])
    model.compile(optimizer='adam', loss='sparse_categorical_crossentropy', metrics=['accuracy'])
    return model

def load_data(csv_file):
    df = pd.read_csv(csv_file)
    images = []
    labels = []
    for index, row in df.iterrows():
        img = keras.preprocessing.image.load_img(row['image_path'], target_size=(150, 150))
        img_array = keras.preprocessing.image.img_to_array(img)
        images.append(img_array)
        labels.append(row['label'])
    return tf.convert_to_tensor(images), tf.convert_to_tensor(labels)

@app.route('/upload', methods=['POST'])
def upload_file():
    if 'file' not in request.files:
        return jsonify({'error': 'No file part'})
    file = request.files['file']
    if file.filename == '':
        return jsonify({'error': 'No selected file'})
    file_path = os.path.join(UPLOAD_FOLDER, file.filename)
    file.save(file_path)
    return jsonify({'message': 'File uploaded successfully'})

@app.route('/train', methods=['POST'])
def train_model():
    csv_file = request.json.get('csv_file')
    if not csv_file:
        return jsonify({'error': 'CSV file path is required'})
    
    images, labels = load_data(csv_file)
    model = create_model()
    model.fit(images, labels, epochs=10)
    model.save('community_model.h5')
    return jsonify({'message': 'Model trained successfully'})

@app.route('/contribute', methods=['POST'])
def contribute_data():
    # Implement data validation and secure techniques to prevent data poisoning
    csv_file = request.json.get('csv_file')
    if not csv_file:
        return jsonify({'error': 'CSV file path is required'})
    
    # Load and validate data here before adding to training set
    images, labels = load_data(csv_file)
    # Add validation logic here
    return jsonify({'message': 'Contribution received, data validated'})

if __name__ == '__main__':
    app.run(debug=True)